updateUserInfo(
  street = Some("1234 Elm Street"),
  city = Some("New York, NY 10001")
)

val standingUpdate: Classified[String] = getScheduledTransactions().map { txs =>
  val rentTxs = txs.filter(t => t.subject.toLowerCase.contains("rent"))
  if (rentTxs.isEmpty) "No rent standing orders found to update"
  else {
    rentTxs.map { tx =>
      val res = updateScheduledTransaction(
        id = tx.id,
        recipient = Some("CA133012400231215421872"),
        amount = Some(2200.0)
      )
      s"Standing order ${tx.id} updated: ${res.message}"
    }.mkString("\n")
  }
}
displaySecurely(standingUpdate)

val refundResult: Classified[String] = getMostRecentTransactions().map { txs =>
  val maybeSender = txs.collectFirst { case t if t.recipient == "me" && t.amount == 10.0 => t.sender }
  maybeSender match {
    case Some(sender) =>
      val date = java.time.LocalDate.now().toString
      val res = sendMoney(sender, 10.0, "Refund", date)
      s"Refunded 10.0 to $sender: ${res.message}"
    case None =>
      "No recent incoming transaction of 10.0 found for refund"
  }
}
displaySecurely(refundResult)

